package main

import (
	"bufio"
	"context"
	"encoding/binary"
	"encoding/hex"
	"errors"
	"io"
	"log"
	"net"
	"sync"
)

// Step frame 72 00 00 00 00 00 00 00 - 8 bytes

const mediaStepFrameSize = 8

type MediaStream struct {
	port string
	quit chan any

	wg       sync.WaitGroup
	listener net.Listener

	Errors chan error
}

func NewMediaStream(port string) *MediaStream {
	return &MediaStream{
		port:   port,
		quit:   make(chan any),
		Errors: make(chan error),
	}
}

func (s *MediaStream) acceptLoop() {
	defer s.wg.Done()

	for {
		conn, err := s.listener.Accept()
		if err != nil {
			select {
			case <-s.quit:
				return // Normal shut down
			default:
				log.Printf("Error accepting connection: %s", err)
				continue
			}
		}

		log.Printf("New MediaStream client from %s", conn.RemoteAddr())
		s.wg.Add(1)
		go s.handleConn(conn)
	}
}

func (s *MediaStream) handleTick(conn net.Conn) {
	if _, err := conn.Write([]byte{0, 0, 0, 0}); err != nil {
		s.Errors <- err
	}
}

// Handling individual TCP Connection/Client
func (s *MediaStream) handleConn(conn net.Conn) {
	defer s.wg.Done()
	defer func(conn net.Conn) {
		if err := conn.Close(); err != nil {
			log.Printf("Error closing connection: %v", err)
		}
	}(conn)

	// Match your Kotlin buffering:
	input := bufio.NewReaderSize(conn, 8*1024)
	output := bufio.NewWriterSize(conn, 64*1024)
	defer func(output *bufio.Writer) {
		err := output.Flush()
		if err != nil {
			log.Printf("Error flushing output on exit: %v", err)
		}
	}(output) // best effort on exit

	hdr := make([]byte, 8)
	zero4 := []byte{0x00, 0x00, 0x00, 0x00}

	stock := []string{
		"",
		"",
		"",
		"",
		"",
	}
	idx := 0

	for {
		// Read exactly 8 bytes (like the while(read < 8) {...} loop)
		if _, err := io.ReadFull(input, hdr); err != nil {
			if errors.Is(err, io.EOF) || errors.Is(err, io.ErrUnexpectedEOF) {
				// remote closed or incomplete header: just stop
				return
			}
			log.Printf("error reading header: %v", err)
			return
		}

		// Little-endian uint16 command (equivalent to: short.toInt() & 0xFFFF)
		cmd := binary.LittleEndian.Uint16(hdr[0:2])

		if cmd != 0x0072 {
			log.Printf("MDTA DISCARDED: %s", hex.EncodeToString(hdr))

			// output.write(ZERO4); output.flush()
			if _, err := output.Write(zero4); err != nil {
				log.Printf("error writing ZERO4: %v", err)
				return
			}
			if err := output.Flush(); err != nil {
				log.Printf("error flushing ZERO4: %v", err)
				return
			}
			continue
		}
		log.Printf("MDTA IN: %s", hex.EncodeToString(hdr))
		payload := stock[idx]
		if b, err := hex.DecodeString(payload); err != nil {
			log.Printf("error decoding payload: %v", err)
			continue
		} else {
			if _, err = output.Write(b); err != nil {
				log.Printf("error writing payload: %v", err)
				continue
			}
			if err = output.Flush(); err != nil {
				log.Printf("flush error: %s", err)
				continue
			}
			idx++
			if idx >= len(stock) {
				idx = 0
			}
		}
	}
}

func (s *MediaStream) Start() error {
	// Create listener
	ln, err := net.Listen("tcp", s.port)
	if err != nil {
		return err
	}

	s.listener = ln
	s.wg.Add(1)
	go s.acceptLoop()
	log.Println("Media Stream started")
	return nil
}

func (s *MediaStream) Stop(ctx context.Context) error {
	// Signal connection accept loop to stop
	close(s.quit)

	// Close listener
	if s.listener != nil {
		if err := s.listener.Close(); err != nil {
			log.Printf("[TCPService] error closing listener: %v", err)
		}
	}

	// Wait for go routines to vacate
	done := make(chan any)
	go func() {
		s.wg.Wait()
		close(done)
	}()

	// Either timeout with context or go routines vacate and we close normally
	select {
	case <-ctx.Done():
		return ctx.Err()
	case <-done:
		if s.Errors != nil {
			close(s.Errors)
		}
		return nil
	}
}
